function romanize(str){let out="";for(const ch of str){const c=ch.charCodeAt(0);
  if(c>=0xAC00&&c<=0xD7A3){const s=c-0xAC00;out+=CHO[Math.floor(s/588)]+JUNG[Math.floor((s%588)/28)]+JONG[s%28];}
  else if(/[0-9a-zA-Z]/.test(ch)) out+=ch.toLowerCase(); else if(ch===" ") out+="-";}
  return out.replace(/-+/g,"-").replace(/^-|-$/g,"")||"loc";}

