/* ===== 변형용: 동의어/헤더/요소 풀 ===== */
const SYN_PHRASE=[["전화 한 통이면","통화 한 번이면","연락 한 번이면"],["빠르게","신속하게"],["추천드립니다","권해드립니다"],["안내드립니다","알려드립니다"],["도와드립니다","챙겨드립니다"]];
const SYN_TOKEN=[["그래서","따라서","그러니"],["또","게다가"],["특히","무엇보다"],["바로","곧","즉시"],["정말","실제로"],["보통","대개"],["가장","제일"],["하지만","그렇지만"]];
function spin(t,key){
  for(let g=0;g<SYN_PHRASE.length;g++){const grp=SYN_PHRASE[g];const ch=grp[hash(key+"sp"+g)%grp.length];if(ch!==grp[0])t=t.split(grp[0]).join(ch);}
  return t.split(" ").map(tok=>{let lead="",trail="",core=tok;
    const L=core.match(/^[(“'"]+/);if(L){lead=L[0];core=core.slice(lead.length);}
    const T=core.match(/[).,!?·”'"]+$/);if(T){trail=T[0];core=core.slice(0,core.length-trail.length);}
    for(let g=0;g<SYN_TOKEN.length;g++){const grp=SYN_TOKEN[g];if(grp.indexOf(core)>=0){const ch=grp[hash(key+"st"+g)%grp.length];return lead+ch+trail;}}
    return tok;}).join(" ");
}
