/* ===== CSS ===== */
const CSS=`
*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent}
:root{--ink:#231d16;--dim:#6f6a60;--paper:#fffdf7;--line:#ece4d2;--bar:70px;
--red:#f5565b;--red-t:#ffecec;--green:#2bb461;--green-t:#e9f9f0;--blue:#4f8dff;--blue-t:#ecf3ff;--amber:#ff9e1b;--amber-t:#fff3e0;--purple:#9b72ff;--purple-t:#f3edff}
body{font-family:'Pretendard',-apple-system,system-ui,'Apple SD Gothic Neo',sans-serif;background:#f3efe6;color:var(--ink);line-height:1.75;font-size:16px;word-break:keep-all}
.wrap{max-width:720px;margin:0 auto;background:var(--paper);min-height:100vh;padding:0 18px calc(var(--bar) + env(safe-area-inset-bottom) + 26px)}
.bc{font-size:12.5px;color:var(--dim);padding:14px 0 4px;display:flex;flex-wrap:wrap;gap:5px;align-items:center}
.bc a{color:var(--dim);text-decoration:none}.bc a:hover{color:var(--blue)}.bc .sep{color:#c8beaa}
.hero{position:relative;border-radius:18px;overflow:hidden;margin:10px 0 14px;background:linear-gradient(135deg,var(--c1),var(--c2));aspect-ratio:1200/630;display:flex;align-items:flex-end;box-shadow:0 16px 34px -16px rgba(0,0,0,.4)}
.hero img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover}
.hero .ov{position:relative;width:100%;padding:20px 18px 16px;background:linear-gradient(to top,rgba(15,12,8,.72),rgba(15,12,8,.15) 70%,transparent);color:#fff}
.hero .tag{display:inline-block;background:rgba(255,255,255,.22);font-size:12px;font-weight:700;padding:4px 10px;border-radius:999px;margin-bottom:8px}
.hero h1{font-size:25px;font-weight:800;color:#fff;line-height:1.3;text-shadow:0 2px 12px rgba(0,0,0,.4)}
.dates{display:flex;gap:14px;flex-wrap:wrap;font-size:12.5px;color:var(--dim);padding:2px 0 10px;border-bottom:1px solid var(--line);margin-bottom:14px}
.dates b{color:var(--ink);font-weight:700}
.lead{font-size:16.5px;color:#3a342b;margin:6px 0 4px}
p{margin:11px 0}
.sh{margin:26px 0 12px}
.sh span{display:inline-flex;align-items:center;gap:7px;padding:8px 15px;border-radius:999px;font-weight:800;font-size:15.5px}
.sh.green span{background:var(--green-t);color:var(--green)}.sh.blue span{background:var(--blue-t);color:var(--blue)}
.sh.amber span{background:var(--amber-t);color:var(--amber)}.sh.purple span{background:var(--purple-t);color:var(--purple)}.sh.red span{background:var(--red-t);color:var(--red)}
.brow{display:flex;align-items:center;gap:11px;padding:13px;border-radius:13px;margin:9px 0;background:#fff;border:1.5px solid var(--line)}
.brow .em{font-size:22px}.brow .l{flex:1;font-weight:700;font-size:15px}.brow .l small{display:block;font-weight:500;font-size:12.5px;color:var(--dim);margin-top:1px}
.brow .v{font-weight:800;white-space:nowrap}.brow .v.free{color:var(--red);font-size:19px}.brow .v.ok{font-size:19px}
.callout{background:var(--ink);color:#fff;border-radius:15px;padding:16px;margin:18px 0;text-align:center;font-weight:800;font-size:16px;display:flex;align-items:center;justify-content:center;gap:7px;flex-wrap:wrap;white-space:nowrap}
.callout .ar{color:#ffd33a}
.chips{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-top:6px}
.chips span{background:#fff;border:1.5px solid var(--line);border-radius:999px;padding:7px 5px;font-size:12.5px;font-weight:700;display:flex;align-items:center;justify-content:center;gap:5px}
.steps{margin-top:6px}.step{display:flex;gap:14px;align-items:flex-start;padding:4px 0}
.step .c{flex:0 0 44px;width:44px;height:44px;border-radius:50%;display:grid;place-items:center;font-weight:800;font-size:19px;color:#fff}
.step.s1 .c{background:var(--blue)}.step.s2 .c{background:var(--amber)}.step.s3 .c{background:var(--green)}
.step h4{font-weight:800;font-size:16px}.step p{font-size:13.5px;color:var(--dim);margin:2px 0 0}
.stepar{font-size:20px;color:#cbc1aa;margin:0 0 0 18px}
.check{background:#fff;border:1.5px solid var(--line);border-radius:14px;padding:14px 16px;margin:6px 0}
.check .ci{display:flex;gap:9px;align-items:center;padding:6px 0;font-weight:600;font-size:14.5px;border-bottom:1px dashed var(--line)}
.check .ci:last-child{border-bottom:0}
.faq{margin-top:4px}.faq .q{font-weight:800;font-size:15px;margin-top:14px;display:flex;gap:7px}.faq .q:first-child{margin-top:0}
.faq .q .qm{color:var(--purple)}.faq .a{font-size:14px;color:var(--dim);margin:5px 0 0;display:flex;gap:7px}.faq .a .am{color:var(--ink);font-weight:700}
.cta{display:flex;align-items:center;gap:9px;justify-content:center;margin:18px 0 0;padding:18px;border-radius:14px;background:var(--green);color:#fff;text-decoration:none;font-weight:800;font-size:18px;box-shadow:0 14px 26px -10px var(--green)}
.cta .ar{font-size:20px}
.tline{font-family:ui-monospace,monospace;text-align:center;color:#bcb29a;margin:18px 0;font-size:12px}
.foot{margin-top:26px;padding-top:18px;border-top:1px solid var(--line);font-size:12.5px;color:var(--dim);line-height:1.95;text-align:center}
.foot .fb{font-weight:800;font-size:15px;color:var(--ink);margin-bottom:7px}.foot a{color:var(--blue);text-decoration:none}
.foot .reg{margin:10px 0;display:flex;flex-wrap:wrap;gap:6px 10px;justify-content:center}.foot .reg a{color:#6f6a60}
.allbtn{display:inline-flex;align-items:center;gap:6px;margin:10px 0;padding:10px 16px;border-radius:999px;background:var(--ink);color:#fff!important;font-weight:700;font-size:13.5px}
.callbar{position:fixed;left:0;right:0;bottom:0;z-index:40;background:var(--ink);padding:10px 14px calc(10px + env(safe-area-inset-bottom))}
.callbar .in{max-width:720px;margin:0 auto}
.callbar a{display:flex;align-items:center;justify-content:center;gap:9px;height:52px;border-radius:13px;background:var(--green);color:#fff;text-decoration:none;font-weight:800;font-size:17px}
.idx{columns:2;column-gap:18px;margin-top:8px}.idx a{display:block;font-size:14px;padding:5px 0;text-decoration:none;color:var(--ink);break-inside:avoid}
.idx a:hover{color:var(--blue)}.idx .alpha{font-weight:800;color:var(--amber);padding:12px 0 4px;break-after:avoid}
.idx a small{color:var(--dim);font-size:11px;margin-left:4px}
.grid2{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:14px 0}
.pcard{display:block;border-radius:16px;padding:20px;text-decoration:none;color:#fff;font-weight:800}
.pcard .pe{font-size:30px;display:block;margin-bottom:6px}.pcard .ps{display:block;font-size:13px;font-weight:600;opacity:.85;margin-top:4px}
.sidogrid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin:12px 0}
.sidocard{display:flex;flex-direction:column;gap:3px;background:#fff;border:1.5px solid var(--line);border-radius:14px;padding:15px 16px;text-decoration:none;color:var(--ink)}
.sidocard .sn{font-size:17px;font-weight:800}
.sidocard .sc{font-size:12.5px;color:var(--dim)}
@media(max-width:520px){.hero h1{font-size:21px}.idx{columns:1}.grid2{grid-template-columns:1fr}.callout{font-size:14px;padding:13px;gap:5px}.sidogrid{grid-template-columns:1fr}}
`;

/* ===== HTML 셸 ===== */
function shell({title,desc,canonical,ogimg,jsonld,body,published,modified}){
  return `<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover">
<title>${esc(title)}</title>
<meta name="description" content="${esc(desc)}">
<link rel="canonical" href="${canonical}">
<link rel="icon" href="/favicon.ico" sizes="any">
<link rel="icon" type="image/svg+xml" href="/favicon.svg">
<link rel="apple-touch-icon" href="/apple-touch-icon.png">
<meta property="og:type" content="article"><meta property="og:title" content="${esc(title)}">
<meta property="og:description" content="${esc(desc)}"><meta property="og:url" content="${canonical}">
<meta property="og:image" content="${ogimg}"><meta property="og:site_name" content="${BRAND}">
<meta name="twitter:card" content="summary_large_image">
${published?`<meta property="article:published_time" content="${published}"><meta property="article:modified_time" content="${modified}">`:""}
<link rel="stylesheet" href="https://cdn.jsdelivr.net/gh/orioncactus/pretendard@v1.3.9/dist/web/static/pretendard.css">
<style>${CSS}</style>
${jsonld?`<script type="application/ld+json">${jsonld}</script>`:""}
</head><body><div class="wrap">${body}</div>
<div class="callbar"><div class="in" style="display:flex;gap:8px"><a href="tel:${TELRAW}" style="flex:1">📞 전화 상담</a><a href="sms:${TELRAW}" style="flex:1;background:var(--blue)">💬 문자 상담</a></div></div>
</body></html>`;
}

