  <div class="ov"><span class="tag">${P.emoji} ${P.name} 설치 · ${esc(name)}</span><h1>${esc(LOC)} ${P.name} 설치<br>무료설치 · 빠른설치 ${P.emoji}</h1></div>
</div>
