const H_HTML={"content-type":"text/html; charset=utf-8","cache-control":"public, max-age=600"};
const H_SVG ={"content-type":"image/svg+xml; charset=utf-8","cache-control":"public, max-age=86400"};
const H_XML ={"content-type":"application/xml; charset=utf-8","cache-control":"public, max-age=3600"};
const H_TXT ={"content-type":"text/plain; charset=utf-8"};
const INDEXNOW_KEY="e248d38dcb33493f936ac720a046d299";
const FAVICON_ICO_B64="";
const APPLE_PNG_B64="";
const FAVICON_SVG=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><defs><clipPath id="r"><rect width="64" height="64" rx="14"/></clipPath></defs><g clip-path="url(#r)"><rect width="64" height="64" fill="#1a1712"/><rect y="51.2" width="64" height="12.8" fill="#ff5a36"/></g><text x="32" y="27" font-family="Arial,Helvetica,sans-serif" font-size="32" font-weight="700" fill="#fff" text-anchor="middle" dominant-baseline="central">24</text></svg>`;
const binResp=(b64,ct)=>new Response(Uint8Array.from(atob(b64),c=>c.charCodeAt(0)),{headers:{"content-type":ct,"cache-control":"public,max-age=2592000"}});

export default {
  async fetch(request){
    const url=new URL(request.url);
    let path=decodeURIComponent(url.pathname).replace(/\/+$/,"")||"/";
    const seg=path.split("/").filter(Boolean);
    if(path==="/") return new Response(HOME_HTML.replace("</head>",homeSchema()+"</head>"),{headers:H_HTML});
    if(path==="/robots.txt") return new Response(robots,{headers:H_TXT});
    if(path===`/${INDEXNOW_KEY}.txt`) return new Response(INDEXNOW_KEY,{headers:H_TXT});
    if(path==="/favicon.ico") return binResp(FAVICON_ICO_B64,"image/x-icon");
    if(path==="/apple-touch-icon.png") return binResp(APPLE_PNG_B64,"image/png");
    if(path==="/favicon.svg") return new Response(FAVICON_SVG,{headers:{"content-type":"image/svg+xml; charset=utf-8","cache-control":"public,max-age=2592000"}});
    if(path==="/llms.txt") return new Response(llms,{headers:H_TXT});
    if(path==="/sitemap.xml") return new Response(sitemap(),{headers:H_XML});
    if(path==="/regions") return new Response(sidoIndex(null),{headers:H_HTML});
    if(path==="/card-terminal"&&seg.length===1) return new Response(sidoIndex("card"),{headers:H_HTML});
    if(path==="/pos"&&seg.length===1) return new Response(sidoIndex("pos"),{headers:H_HTML});
    if((seg[0]==="card-terminal"||seg[0]==="pos"||seg[0]==="regions")&&seg[1]==="sido"){
      const t=seg[0]==="card-terminal"?"card":seg[0]==="pos"?"pos":null;
      let h=null;
      if(seg.length===3) h=gugunIndex(t,seg[2]);
      else if(seg.length===4) h=gugunDetail(t,seg[2],seg[3]);
      if(h) return new Response(h,{headers:H_HTML});
    }
    if(seg[0]==="thumb"&&seg.length===3) return new Response(thumbSvg(seg[1],seg[2].replace(/\.svg$/,"")),{headers:H_SVG});
    if((seg[0]==="card-terminal"||seg[0]==="pos")&&seg.length===2){
      const html=productPage(seg[0]==="pos"?"pos":"card",seg[1]);
      if(html) return new Response(html,{headers:H_HTML});
    }
    return new Response(notFound(),{status:404,headers:H_HTML});
  }
};
function notFound(){
  return shell({title:`페이지를 찾을 수 없어요 | ${BRAND}`,desc:"요청하신 페이지가 없습니다.",canonical:SITE+"/",ogimg:`${SITE}/thumb/card/seoul.svg`,jsonld:"",
    body:`<div style="padding:60px 0;text-align:center"><div style="font-size:54px">🧾</div><h1 style="font-size:24px;margin:14px 0">페이지를 찾을 수 없어요</h1><p>주소를 다시 확인해 주세요.</p><a class="allbtn" href="/regions">📍 전체지역 보기 →</a><div style="margin-top:18px"><a href="/" style="color:var(--blue)">홈으로</a></div>${footer("","")}</div>`});
}
